    color.rgb = clamp(phosphorColor, 0.0, 1.0);
    color.rgb = applyLumaToneCompression(color.rgb);
    color.rgb = applySaturationToneCompression(color.rgb);
    color.rgb = clamp(color.rgb * uOutputBrightness, 0.0, 1.0);
